package tournament.presentation;
import java.util.Scanner; import tournament.application.*; import tournament.domain.factory.TournamentFactory; import tournament.infrastructure.auth.*; import tournament.infrastructure.repository.*;
public class Main { public static void main(String[] args){ TournamentRepository tournamentRepository=new InMemoryTournamentRepository(); AuditRepository auditRepository=new InMemoryAuditRepository(); AuthAdapter authAdapter=new AuthAdapter(new SimpleExternalAuthProvider()); AuditService auditService=new AuditService(auditRepository); TournamentService tournamentService=new TournamentService(tournamentRepository,new TournamentFactory(),authAdapter,auditService); MatchService matchService=new MatchService(tournamentRepository,authAdapter,auditService); StandingsService standingsService=new StandingsService(tournamentRepository); DisputeService disputeService=new DisputeService(tournamentRepository,authAdapter,auditService); TournamentConsoleUI ui=new TournamentConsoleUI(tournamentService,matchService,standingsService,disputeService,auditService); DemoRunner demoRunner=new DemoRunner(tournamentService,matchService,standingsService,disputeService,ui); Scanner sc=new Scanner(System.in); System.out.println("Tournament Demo\n1. Scripted demo\n2. Manual testing"); System.out.print("Choose mode: "); String choice=sc.nextLine().trim(); if("1".equals(choice)) demoRunner.runScriptedDemo(); else ui.start(); } }
